import java.util.*;public class FirstLastOccurrence{static int f(int[]a,int x){int l=0,r=a.length-1,ans=-1;while(l<=r){int m=l+(r-l)/2;if(a[m]>=x){if(a[m]==x)ans=m;r=m-1;}else l=m+1;}return ans;}static int g(int[]a,int x){int l=0,r=a.length-1,ans=-1;while(l<=r){int m=l+(r-l)/2;if(a[m]<=x){if(a[m]==x)ans=m;l=m+1;}else r=m-1;}return ans;}public static void main(String[]z){Scanner s=new Scanner(System.in);int n=s.nextInt();int[]a=new int[n];for(int i=0;i<n;i++)a[i]=s.nextInt();int t=s.nextInt();System.out.println(f(a,t));System.out.println(g(a,t));}}